// Worked focus: httpsts-route-order-shadowing — Derive dispatch from registration order, method, path, router mounting, next-route behavior, and literal-versus-parameter overlap.
// Evidence: httpsts-worked-http-server-ts-express-routing-paths-2
// Competency: httpsts-worked-http-server-ts-express-routing-paths-2.
// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_express_routing_paths_2(method: string, path: string, wildcardParts: readonly string[]): { route: string; status: number } {
  const normalized = method.toUpperCase();
  if (normalized === "GET" && path === "/incidents/latest") {
    return { route: "GET /incidents/latest", status: 200 };
  }
  if (normalized === "GET" && wildcardParts.length === 1) {
    return { route: "GET /incidents/{*parts}", status: 200 };
  }
  return { route: "unmatched", status: 404 };
}

